import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const FormBuilder = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    title: '',
    fields: []
  });

  const [newField, setNewField] = useState({
    label: '',
    type: 'text',
    required: false
  });

  const addField = () => {
    if (newField.label.trim()) {
      setFormData({
        ...formData,
        fields: [...formData.fields, { ...newField }]
      });
      setNewField({ label: '', type: 'text', required: false });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:5001/api/forms', formData);
      navigate('/');
    } catch (error) {
      console.error('Error creating form:', error);
    }
  };

  return (
    <div className="form-builder">
      <h2>Create New Form</h2>
      <div className="form-section">
        <input
          type="text"
          placeholder="Form Title"
          value={formData.title}
          onChange={(e) => setFormData({ ...formData, title: e.target.value })}
          className="form-input"
        />
      </div>

      <div className="field-creator">
        <h3>Add Field</h3>
        <div className="field-inputs">
          <input
            type="text"
            placeholder="Field Label"
            value={newField.label}
            onChange={(e) => setNewField({ ...newField, label: e.target.value })}
            className="form-input"
          />
          <select
            value={newField.type}
            onChange={(e) => setNewField({ ...newField, type: e.target.value })}
            className="form-select"
          >
            <option value="text">Text</option>
            <option value="number">Number</option>
            <option value="email">Email</option>
            <option value="date">Date</option>
            <option value="textarea">Text Area</option>
          </select>
          <label>
            <input
              type="checkbox"
              checked={newField.required}
              onChange={(e) => setNewField({ ...newField, required: e.target.checked })}
            />
            Required
          </label>
          <button onClick={addField} className="btn">Add Field</button>
        </div>
      </div>

      <div className="fields-preview">
        <h3>Form Fields</h3>
        {formData.fields.map((field, index) => (
          <div key={index} className="field-preview">
            <p>{field.label} ({field.type}){field.required ? ' *' : ''}</p>
          </div>
        ))}
      </div>

      <button onClick={handleSubmit} className="btn submit-btn">
        Create Form
      </button>
    </div>
  );
};

export default FormBuilder;
